# Python 3.11+
"""Discount policies ŌĆö the seam that decides how an order-level discount is applied.

The Decorator handles per-DRINK pricing; this Strategy handles per-ORDER discounts.
They're deliberately separate: an add-on changes one drink's cost, a discount
changes the whole basket's total. The orchestrator never hardcodes "10% off" ŌĆö it
holds a `DiscountStrategy` and asks it for the amount to subtract.

­¤ÄÖ’ĖÅ "Discounts are exactly the thing the business tweaks weekly ŌĆö none today,
percent-off tomorrow, a combo deal next week. So it's a Strategy: each rule is one
class, and place_order just asks 'how much off?' without knowing which rule it is."
"""

from abc import ABC, abstractmethod
from decimal import Decimal

from models import to_money


class DiscountStrategy(ABC):
    # ŌöĆŌöĆ WHY THIS CLASS ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    # The abstraction OrderService depends on (Dependency Inversion). Given a
    # subtotal it returns the AMOUNT to subtract ŌĆö never the final total ŌĆö so the
    # service stays in charge of the arithmetic and the strategy stays a pure rule.
    name: str = "none"

    @abstractmethod
    def apply(self, subtotal: Decimal) -> Decimal:
        """Return the discount amount (>= 0, never more than the subtotal)."""
        raise NotImplementedError


class NoDiscount(DiscountStrategy):
    """Default: charge full price. Subtracting zero keeps place_order branch-free."""

    name = "none"

    def apply(self, subtotal: Decimal) -> Decimal:
        return Decimal("0.00")


class PercentOffDiscount(DiscountStrategy):
    """Take a percentage off the whole order (e.g. a 10%-off coupon)."""

    def __init__(self, percent: Decimal | int) -> None:
        self._percent = Decimal(percent)
        # WHY: build the human label once so the receipt and tests can read it.
        self.name = f"{self._percent.normalize()}% off"

    def apply(self, subtotal: Decimal) -> Decimal:
        # WHY: clamp at the subtotal so a 200%-off coupon can never make us PAY
        #      the customer ŌĆö the discount is at most the whole order.
        raw = subtotal * self._percent / Decimal(100)
        return min(to_money(raw), subtotal)


class ComboDiscount(DiscountStrategy):
    """Flat amount off once the order crosses a threshold (a 'meal combo' deal)."""

    def __init__(self, threshold: Decimal, amount: Decimal) -> None:
        self._threshold = Decimal(threshold)
        self._amount = Decimal(amount)
        self.name = f"combo -{to_money(self._amount)} over {to_money(self._threshold)}"

    def apply(self, subtotal: Decimal) -> Decimal:
        if subtotal >= self._threshold:
            # WHY: never discount below zero ŌĆö a tiny combo can't go negative.
            return min(to_money(self._amount), subtotal)
        return Decimal("0.00")

